import{_ as a,o as i,c as t,ae as l}from"./chunks/framework.DeBUZsJm.js";const p=JSON.parse('{"title":"Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"troubleshooting.md","filePath":"troubleshooting.md","lastUpdated":1775513914000}'),n={name:"troubleshooting.md"};function o(r,e,s,d,u,h){return i(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h1><h2 id="plugin-does-not-appear-in-the-list" tabindex="-1">Plugin does not appear in the list <a class="header-anchor" href="#plugin-does-not-appear-in-the-list" aria-label="Permalink to &quot;Plugin does not appear in the list&quot;">​</a></h2><p>Check these first:</p><ul><li>the file ends with <code>.tgd</code></li><li>it is placed in <code>&lt;working dir&gt;/tdata/plugins</code></li><li>the client and plugin architectures match</li><li>the plugin was built against the current Astrogram plugin API</li></ul><h2 id="plugin-loads-as-metadata-only" tabindex="-1">Plugin loads as metadata only <a class="header-anchor" href="#plugin-loads-as-metadata-only" aria-label="Permalink to &quot;Plugin loads as metadata only&quot;">​</a></h2><p>Astrogram can read preview metadata without fully executing plugin code.</p><p>Common reasons a plugin remains metadata-only:</p><ul><li>it is disabled</li><li>it was disabled by recovery after a crash</li><li>ABI mismatch</li><li>entry point not found</li></ul><h2 id="safe-mode-turned-on-after-a-crash" tabindex="-1">Safe mode turned on after a crash <a class="header-anchor" href="#safe-mode-turned-on-after-a-crash" aria-label="Permalink to &quot;Safe mode turned on after a crash&quot;">​</a></h2><p>When a tracked plugin operation crashes the client, Astrogram may:</p><ol><li>enable safe mode</li><li>disable the implicated plugin</li><li>keep the plugin visible in the manager</li><li>record details in <code>plugins.log</code> and recovery state files</li></ol><p>Check:</p><ul><li><code>&lt;working dir&gt;/tdata/plugins.safe-mode</code></li><li><code>&lt;working dir&gt;/tdata/plugins.recovery.json</code></li><li><code>&lt;working dir&gt;/tdata/plugins.log</code></li></ul><h2 id="common-plugin-loading-failures" tabindex="-1">Common plugin loading failures <a class="header-anchor" href="#common-plugin-loading-failures" aria-label="Permalink to &quot;Common plugin loading failures&quot;">​</a></h2><h3 id="cannot-load-library" tabindex="-1">&quot;Cannot load library&quot; <a class="header-anchor" href="#cannot-load-library" aria-label="Permalink to &quot;&quot;Cannot load library&quot;&quot;">​</a></h3><p>Usually means one of these:</p><ul><li>missing dependent DLL</li><li>Qt version mismatch</li><li>compiler runtime mismatch</li><li>incorrect exported plugin entry point</li></ul><h3 id="plugin-installs-but-does-nothing" tabindex="-1">Plugin installs but does nothing <a class="header-anchor" href="#plugin-installs-but-does-nothing" aria-label="Permalink to &quot;Plugin installs but does nothing&quot;">​</a></h3><p>Typical causes:</p><ul><li>your plugin never registers observers or settings callbacks</li><li>it expects a window/session too early during startup</li><li>it only reacts to commands and none were invoked</li></ul><h3 id="client-crashes-when-opening-plugin-settings" tabindex="-1">Client crashes when opening plugin settings <a class="header-anchor" href="#client-crashes-when-opening-plugin-settings" aria-label="Permalink to &quot;Client crashes when opening plugin settings&quot;">​</a></h3><p>Prefer host-rendered settings pages over raw plugin-owned dialogs. Host-rendered controls are the stable UI path in Astrogram.</p><h2 id="what-to-include-in-a-bug-report" tabindex="-1">What to include in a bug report <a class="header-anchor" href="#what-to-include-in-a-bug-report" aria-label="Permalink to &quot;What to include in a bug report&quot;">​</a></h2><ul><li>client build identifier</li><li>exact plugin version</li><li>steps to reproduce</li><li>the relevant tail of <code>plugins.log</code></li><li>whether the problem happens only after restart or immediately after install</li></ul>',24)])])}const g=a(n,[["render",o]]);export{p as __pageData,g as default};
